// 1. Extraer el texto crudo que devuelve el LLM
const raw = $json.text || $json.output || $json.response || JSON.stringify($json);

// 2. Limpiar posibles bloques markdown que DeepSeek añade
const clean = raw
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .trim();

// 3. Parsear el JSON
let aiResult;
try {
  aiResult = JSON.parse(clean);
} catch(e) {
  // Si falla el parse, devolver error con el raw para debug
  return [{
    json: {
      parse_error: true,
      error_message: e.message,
      raw_output: raw
    }
  }];
}

// 4. Recuperar datos originales del Webhook (php_detected_host_ids, sold_to, etc.)
const webhookBody = $("Webhook").item.json.body || {};

// 5. Merge: los datos de la IA tienen prioridad, pero conservamos campos PHP si la IA no los tiene
const merged = {
  ...webhookBody,
  ...aiResult,
  // Asegurar que sold_to nunca se pierda
  sold_to: aiResult.sold_to || webhookBody.sold_to || 'unknown'
};

return [{ json: merged }];
